// ══════════════════════════════════════════════════════════════
//  EduDesk OnPrem — Startup License Validation
//  CloudTitans © 2026
//
//  Runs once when the Next.js server starts.
//  Crashes the process if the license is invalid.
//  Only active when NEXT_PUBLIC_MODE=onprem
// ══════════════════════════════════════════════════════════════

export async function register() {
  // Only run in Node.js runtime (not Edge), and only in onprem mode
  if (process.env.NEXT_RUNTIME !== 'nodejs') return
  if (process.env.NEXT_PUBLIC_MODE !== 'onprem') return

  try {
    const { validateLicense }  = await import('./lib/license-validator')
    const { getLicenseStatus } = await import('./lib/license')

    const license = validateLicense()
    const status  = getLicenseStatus(license)

    // Cache on global so API routes can read feature limits at runtime
    ;(globalThis as any).__edudesk_license__        = license
    ;(globalThis as any).__edudesk_license_status__ = status

    console.log('')
    console.log('══════════════════════════════════════════════')
    console.log('  EduDesk License Validated ✓')
    console.log(`  Licensee  : ${license.licensee}`)
    console.log(`  Type      : ${license.type}`)
    console.log(`  Domain    : ${license.domain}`)
    if (license.type === 'DEMO' && license.trialEndsAt) {
      if (status.expired) {
        console.log(`  Trial     : EXPIRED (${license.trialEndsAt})`)
        console.log('  ⚠️  App running in read-only mode')
      } else {
        console.log(`  Trial     : expires ${license.trialEndsAt} (${status.daysLeft} days left)`)
      }
    } else {
      console.log(`  Updates   : until ${license.updatesUntil ?? 'N/A'}`)
    }
    console.log(`  Max Users : ${license.features.maxUsers}`)
    console.log(`  Max Agents: ${license.features.maxAgents}`)
    console.log(`  Branding  : ${license.features.branding}`)
    console.log(`  Integrtns : ${(license.features as any).integrations ?? (license.features as any).adSync ?? false}`)
    console.log('══════════════════════════════════════════════')
    console.log('')

    // ── Sync license features → DB (non-fatal) ────────────────
    // Ensures brandingEnabled, adEnabled, maxUsers, maxAgents in the DB
    // always reflect the current license key, even after a key upgrade.
    try {
      const { prisma } = await import('./lib/prisma')
      const tenant = await prisma.tenant.findFirst()
      if (tenant) {
        // Support both new 'integrations' flag and legacy 'adSync/azureSync/googleSync' flags
        const feat = license.features as any
        const integrationsEnabled =
          feat.integrations === true ||
          feat.adSync       === true ||
          feat.azureSync    === true ||
          feat.googleSync   === true

        // Update tenant feature flags
        await prisma.$executeRaw`
          UPDATE tenants SET
            brandingEnabled = ${license.features.branding ? 1 : 0},
            adEnabled       = ${integrationsEnabled       ? 1 : 0}
          WHERE id = ${tenant.id}
        `
        // Update SaaS license table so the users API reads the right limits
        await prisma.license.updateMany({
          where: { tenantId: tenant.id },
          data: {
            maxUsers:     license.features.maxUsers,
            maxAgents:    license.features.maxAgents,
            maxStorageMb: license.features.maxStorageMb,
          },
        })
        console.log('  License features synced to DB ✓')
        console.log('')
      }
    } catch (syncErr: any) {
      // Non-fatal — app still works; DB will sync on next restart
      console.warn(`  ⚠️  License DB sync skipped: ${syncErr.message}`)
      console.log('')
    }

  } catch (err: any) {
    console.error('')
    console.error('══════════════════════════════════════════════')
    console.error('  ❌  EduDesk — License Error')
    console.error('')
    console.error(`  ${err.message.split('\n').join('\n  ')}`)
    console.error('')
    console.error('  Contact: support@ctitans.com')
    console.error('══════════════════════════════════════════════')
    console.error('')
    process.exit(1)
  }
}
